def solve(nums: list[int]) -> int:
    n = len(nums)
    max_sum = 0

    # Iterate all possible masks for A and B (each bit represents if the element is in A, B, or C)
    # Since each element can be in A, B, or C, we can represent the partition with two masks:
    # mask_a and mask_b, where mask_a & mask_b == 0 (no overlap)
    # The remaining elements (not in A or B) are in C
    for mask_a in range(1 << n):
        for mask_b in range(1 << n):
            if mask_a & mask_b != 0:
                continue  # A and B must be disjoint

            xor_a = 0
            and_b = ~0  # Initialize to all 1s for AND operation
            xor_c = 0

            for i in range(n):
                if mask_a & (1 << i):
                    xor_a ^= nums[i]
                elif mask_b & (1 << i):
                    and_b &= nums[i]
                else:
                    xor_c ^= nums[i]

            # Handle empty B case (AND of empty is 0)
            if mask_b == 0:
                and_b = 0

            current_sum = xor_a + and_b + xor_c
            if current_sum > max_sum:
                max_sum = current_sum

    return max_sum
